-- Add the unique constraint that the useWeeklyGoals upsert relies on. The hook writes student_id, week_start_date, and goal_type; without this index Postgres rejects the ON CONFLICT clause with "there is no unique or exclusion constraint matching the ON CONFLICT specification". Backfill week_start_date from week_start for any existing rows where it is null. UPDATE public.weekly_goals SET week_start_date = week_start WHERE week_start_date IS NULL; -- Make week_start_date NOT NULL so the unique index is well-defined. ALTER TABLE public.weekly_goals ALTER COLUMN week_start_date SET NOT NULL; -- The unique constraint that powers the upsert. CREATE UNIQUE INDEX IF NOT EXISTS uq_weekly_goals_student_week_type ON public.weekly_goals (student_id, week_start_date, goal_type);;
